import React, { useEffect } from "react";
import axios from 'axios'
import Journal from "./Journal";
import ConfirmationAlert from './ConfirmationAlert'
import { useNavigate, useParams } from "react-router-dom";

const JournalCard = ({ id, title, date, entry, analyzed, analysis, onEdit }) => {
  const [message,setMessage]=useState('')
  const navigate = useNavigate();
  async function onEdit(editEntryId) {
    navigate(`/journal/${editEntryId}`);
  }
 
  // async function onDelete(id) {
  //   const deleteEntry = await axios.delete(`/api/journal/deleteJournal/${id}`,
  //     {
  //       headers: {
  //         'Authorization': "Bearer eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpZCI6IjY4N2U3Y2QxNjdlYzBhMjRkYzg5YmM4MCIsImVtYWlsIjoiYWRtaW5AZ21haWwuY29tIiwiaWF0IjoxNzUzNzIyNzg5fQ.JVkON-9dwOeHhwE7mHGn5ZcXs5kiW87Z1E2NxccOXFE"
  //       }
  //     })
  // }

    const onDelete = async (id) => {
    if (window.confirm("Are you sure you want to delete this Journal?")) {
      const deleteAnalysis = await axios.delete(`/api/journal/deleteJournal/${id}`,
        {
          headers: {
            'Authorization': "Bearer eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpZCI6IjY4N2U3Y2QxNjdlYzBhMjRkYzg5YmM4MCIsImVtYWlsIjoiYWRtaW5AZ21haWwuY29tIiwiaWF0IjoxNzUzNzcyMzA2fQ.dh1DnP1EpY1i1JcBxRIrOIHJhQ0fUgQQo5VsIsbpJOM"
          }
        })
    }
  };

  const previewLines = entry.split("\n").slice(0, 2).join("\n");

  return (
    <div className="journal-card">
        <ConfirmationAlert/>
      {title && <h3 className="card-title">{title}</h3>}
      <p className="card-date">{date}</p>
      <div className="card-status">
        Status:{" "}
        <span className={analyzed ? "status-analyzed" : "status-not-analyzed"}>
          {analyzed ? "Analyzed" : "Not Analyzed"}
        </span>
      </div>
      <pre className="card-preview">{previewLines}</pre>

      {analyzed && analysis && (
        <div className="card-analysis">{analysis}</div>
      )}

      <div className="card-actions">
        <button onClick={() => onEdit(id)}>Edit</button>
        <button onClick={() => onDelete(id)}>Delete</button>
      </div>
      <Stylesheet />
    </div>
  );
};
// async function JournalWrapper() {
//   const { id } = useParams();
//   const navigate = useNavigate();
//   // After save or cancel, return to history page
//   const onSaveComplete = () => {
//     navigate('/history');
//   };

//   return <Journal editEntryId={id ? id : null} onSaveComplete={onSaveComplete} />;
// }
const Stylesheet = () => {
  return <style>{`
        .journal-card {
          background-color: var(--secondary-color);
          color: var(--text);
          border-radius: 8px;
          padding: 1rem;
          width: 200px;
          height: 200px;
          box-shadow: 0 2px 6px rgba(0, 0, 0, 0.15);
          display: flex;
          flex-direction: column;
          justify-content: space-between;
        }

        .card-title {
          font-size: 1.1rem;
          margin: 0 0 0.2rem;
        }

        .card-date {
          font-size: 0.85rem;
          opacity: 0.7;
          margin-bottom: 0.5rem;
        }

        .card-preview {
          font-size: 0.85rem;
          font-family: 'Cedarville Cursive', cursive;
          flex-grow: 1;
          margin-bottom: 0.5rem;
          overflow: hidden;
          text-overflow: ellipsis;
        }

        .card-status {
          font-size: 0.85rem;
        }

        .status-analyzed {
          color: green;
          font-weight: bold;
        }

        .status-not-analyzed {
          color: red;
          font-weight: bold;
        }

        .card-analysis {
          font-size: 0.75rem;
          font-style: italic;
          margin-top: 0.3rem;
        }

        .card-actions {
          display: flex;
          justify-content: space-between;
          margin-top: 0.5rem;
        }

        .card-actions button {
          font-size: 0.8rem;
          font-family: 'Cedarville Cursive', cursive;
          padding: 4px 8px;
          border: none;
          border-radius: 4px;
          cursor: pointer;
          background-color: var(--button-color);
          color: var(--bg-parchment);
        }

        .card-actions button:hover {
          opacity: 0.85;
        }
        
        @media (max-width:300){
            .journal-card{
              height: auto;
            }
        }
      `}</style>
}
export default JournalCard;
